  COOLDOWN_SEC: Math.max(0, Math.min(3600, Math.floor(num("COOLDOWN_SEC", 20)))),
  CONCURRENCY: Math.max(1, Math.min(8, Math.floor(num("CONCURRENCY", 2)))),

