      import { getDb } from "./db.js";

const COL = "memory_messages";

export async function addTurn({ mongoUri, platform, userId, chatId, role, text }) {
  const db = await getDb(mongoUri);
  const doc = {
    platform,
    userId: String(userId),
    chatId: chatId ? String(chatId) : "",
    role,
    text: String(text || "").slice(0, 4000),
    ts: new Date(),
  };

  if (!db) return; // allow bot to run without DB
  await db.collection(COL).insertOne(doc);
}

export async function getRecentTurns({ mongoUri, platform, userId, chatId, limit = 14 }) {
  const db = await getDb(mongoUri);
  if (!db) return [];

  const q = {
    platform,
    userId: String(userId),
  };
  if (chatId) q.chatId = String(chatId);

  const rows = await db
    .collection(COL)
    .find(q)
    .sort({ ts: -1 })
    .limit(limit)
    .toArray();

  // return chronological
  return rows.reverse().map((r) => ({ role: r.role, text: r.text }));
}

export async function clearUserMemory({ mongoUri, platform, userId, chatId }) {
  const db = await getDb(mongoUri);
  if (!db) return;

  const q = { platform, userId: String(userId) };
  if (chatId) q.chatId = String(chatId);

  await db.collection(COL).deleteMany(q);
}

queue.js.content:
import { safeErr } from "./errors.js";

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

export function createQueue({ concurrency = 2, log }) {
  let active = 0;
  const pending = [];
  let pumping = false;

  function state() {
    return { concurrency, active, pending: pending.length };
  }

  async function pump() {
    if (pumping) return;
    pumping = true;

    try {
      log.info("queue pump start", state());

      while (active < concurrency && pending.length > 0) {
        const item = pending.shift();
        active += 1;

        const startedAt = Date.now();
        log.info("queue job begin", { ...state(), jobId: item.jobId });

        (async () => {
          try {
            await item.fn();
            log.info("queue job success", { jobId: item.jobId, ms: Date.now() - startedAt });
          } catch (e) {
            log.error("queue job failed", { jobId: item.jobId, err: safeErr(e), ms: Date.now() - startedAt });
          } finally {
            active -= 1;
            log.info("queue job end", { ...state(), jobId: item.jobId });
            await sleep(0);
            pump();
          }
        })();
      }

      log.info("queue pump idle", state());
    } finally {
      pumping = false;
    }
  }

  function enqueue(fn) {
    const jobId = `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
    const item = { jobId, fn };

    pending.push(item);

    const pos = Math.max(0, pending.length - 1 - Math.max(0, concurrency - active - 1));
    log.info("queue enqueue", { jobId, position: pending.length, ...state() });

    pump();

    // Return user's queue position estimate: if active < concurrency and this job is at head, it's 0
    // We'll compute real position in caller by looking at current state; keep it simple.
    return pending.length > 0 && active >= concurrency ? pending.length : 0;
  }

  return { enqueue, state };
}

validators.js.content:
import dns from "node:dns/promises";
import net from "node:net";

import { UserError } from "./errors.js";

function hasSpacesOrControl(s) {
  // reject spaces and ASCII control chars
  return /[\s\x00-\x1F\x7F]/.test(String(s || ""));
}

function isLocalhostHost(hostname) {
  const h = String(hostname || "").toLowerCase();
  return h === "localhost" || h.endsWith(".localhost");
}

function ipIsPrivateV4(ip) {
  const parts = String(ip || "").split(".").map((x) => Number(x));
  if (parts.length !== 4 || parts.some((n) => !Number.isInteger(n) || n < 0 || n > 255)) return false;

  const [a, b] = parts;
  if (a === 127) return true;
  if (a === 10) return true;
  if (a === 192 && b === 168) return true;
  if (a === 172 && b >= 16 && b <= 31) return true;
  return false;
}

function isIpHostname(hostname) {
  return net.isIP(String(hostname || "")) !== 0;
}

export async function verifyAndNormalizeUrl(raw) {
  const input = String(raw || "").trim();

  if (!input) {
    throw new UserError(
      "INVALID_URL",
      "Invalid URL. Usage: /dl <url>\nExample: /dl https://example.com/video"
    );
  }

  if (hasSpacesOrControl(input)) {
    throw new UserError("INVALID_URL", "Invalid URL: spaces or control characters are not allowed.");
  }

  let u;
  try {
    u = new URL(input);
  } catch {
    throw new UserError(
      "INVALID_URL",
      "Invalid URL. Usage: /dl <url>\nExample: /dl https://example.com/video"
    );
  }

  if (u.protocol !== "http:" && u.protocol !== "https:") {
    throw new UserError("INVALID_URL", "Invalid URL: only http:// or https:// URLs are allowed.");
  }

  if (u.username || u.password) {
    throw new UserError("INVALID_URL", "Invalid URL: username/password in URLs is not allowed.");
  }

  if (!u.hostname) {
    throw new UserError("INVALID_URL", "Invalid URL: missing hostname.");
  }

  if (isLocalhostHost(u.hostname)) {
    throw new UserError("BLOCKED_URL", "Blocked URL: localhost addresses are not allowed.");
  }

  // Reject direct IP hostnames if private
  if (isIpHostname(u.hostname)) {
    const ip = u.hostname;
    if (net.isIP(ip) === 4 && ipIsPrivateV4(ip)) {
      throw new UserError("BLOCKED_URL", "Blocked URL: private/local network addresses are not allowed.");
    }
  }

  // Resolve DNS A records and block if any private
  let addrs;
  try {
    addrs = await dns.resolve4(u.hostname);
  } catch (e) {
    throw new UserError("DNS_FAIL", "DNS lookup failed for this hostname. Please use a public URL.");
  }

  if (!Array.isArray(addrs) || addrs.length === 0) {
    throw new UserError("DNS_FAIL", "DNS lookup failed for this hostname. Please use a public URL.");
  }

  for (const ip of addrs) {
    if (ipIsPrivateV4(ip)) {
      throw new UserError("BLOCKED_URL", "Blocked URL: private/local network addresses are not allowed.");
    }
  }

  // Normalize (WHATWG URL serialization)
  const normalized = u.toString();
  return { url: u, normalized };
}
